import{_ as i,o as s,c as e,a5 as t}from"./chunks/framework.COADHF96.js";const g=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md","lastUpdated":1781779105000}'),n={name:"guide/installation.md"};function l(o,a,r,h,c,p){return s(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>There are three ways to use AI Playground outside the web app — the <strong>gen-ai CLI</strong>, ready-to-use <strong>Skills</strong> for AI agents, and the <strong>MCP</strong> integration. They all build on the same account: install the CLI, run <code>gen-ai login</code> once, and everything else builds on it.</p><h2 id="gen-ai-cli" tabindex="-1">gen-ai CLI <a class="header-anchor" href="#gen-ai-cli" aria-label="Permalink to &quot;gen-ai CLI&quot;">​</a></h2><h3 id="install-script-—-macos-linux" tabindex="-1">Install script — macOS / Linux <a class="header-anchor" href="#install-script-—-macos-linux" aria-label="Permalink to &quot;Install script — macOS / Linux&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://picsart.com/gen-ai-cli/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>This installs the <code>gen-ai</code> binary to <code>~/.local/bin</code> (override with <code>GEN_AI_INSTALL_DIR</code>), verifies SHA-256 checksums, and adds the install dir to your <code>PATH</code> via your shell rc (<code>.bashrc</code> / <code>.zshrc</code> / <code>.profile</code> / fish). Supports macOS and Linux on x64 and arm64.</p><h3 id="install-script-—-windows-powershell" tabindex="-1">Install script — Windows PowerShell <a class="header-anchor" href="#install-script-—-windows-powershell" aria-label="Permalink to &quot;Install script — Windows PowerShell&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">iwr https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">picsart.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gen</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cli</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><h3 id="npm-any-platform" tabindex="-1">npm (any platform) <a class="header-anchor" href="#npm-any-platform" aria-label="Permalink to &quot;npm (any platform)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @picsart/gen-ai</span></span></code></pre></div><h3 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gen-ai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>Then authenticate once with <code>gen-ai login</code> — see <strong><a href="/picsart-mcp-cli-docs/guide/authentication">Authentication</a></strong>.</p><blockquote><p>Official page: <a href="https://picsart.com/gen-ai-cli/" target="_blank" rel="noreferrer">picsart.com/gen-ai-cli</a></p></blockquote><h2 id="skills-—-for-ai-agents" tabindex="-1">Skills — for AI agents <a class="header-anchor" href="#skills-—-for-ai-agents" aria-label="Permalink to &quot;Skills — for AI agents&quot;">​</a></h2><p>Picsart ships ready-to-use <strong>Skills</strong>: small <code>.zip</code> bundles of prompts and instructions that drop straight into <strong>Claude Code, Cursor, Windsurf, or ChatGPT</strong>. Download a skill, hand it to the agent, and it already knows which model to pick, how to structure the prompt, and which <code>gen-ai</code> command to run. The flagship skill, <strong><code>gen-ai-use</code></strong>, gives an agent access to all 130+ models across image, video, and audio.</p><p>Skills drive the <code>gen-ai</code> CLI under the hood, so install the CLI and run <code>gen-ai login</code> first. Full walkthrough in the <strong><a href="/picsart-mcp-cli-docs/guide/skills">Skills guide</a></strong>.</p><blockquote><p>Official page: <a href="https://picsart.com/gen-ai-skills/" target="_blank" rel="noreferrer">picsart.com/gen-ai-skills</a></p></blockquote><h2 id="mcp-agent-integrations" tabindex="-1">MCP &amp; agent integrations <a class="header-anchor" href="#mcp-agent-integrations" aria-label="Permalink to &quot;MCP &amp; agent integrations&quot;">​</a></h2><p>The gen-ai integration is built on the <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">Model Context Protocol</a>, so it works natively with <strong>Claude Code, Cursor, Windsurf, ChatGPT, or any MCP-compatible agent</strong> — connecting to 130+ models (Flux, Sora, Kling, Veo, ElevenLabs, and more).</p><ul><li><p><strong>Claude Code / Cursor / Windsurf</strong> — add the <a href="/picsart-mcp-cli-docs/guide/skills"><code>gen-ai-use</code> Skill</a>; it plugs the CLI into the agent.</p></li><li><p><strong>Codex (OpenAI)</strong> — install the CLI, then add the plugin:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codex://plugins/picsart@openai-curated</span></span></code></pre></div></li><li><p><strong>Any MCP client</strong> — see the official MCP page for the current connection method and the available tools.</p></li></ul><p>Authentication is always <code>gen-ai login</code> (one browser confirmation per machine).</p><blockquote><p>Official page: <a href="https://picsart.com/gen-ai-mcp/" target="_blank" rel="noreferrer">picsart.com/gen-ai-mcp</a> — the canonical, always-current connection details live here. The <strong><a href="/picsart-mcp-cli-docs/guide/mcp-quickstart">MCP Quickstart</a></strong> documents the agent-facing tools (<code>picsart_generate</code>, <code>picsart_pricing</code>, …) and example calls.</p></blockquote>',23)])])}const k=i(n,[["render",l]]);export{g as __pageData,k as default};
